Here is the JavaScript code to calculate the factorial of x:

```javascript
let x = 7;

function calculateFactorial(n) {
  if (n < 0) {
    throw new Error("Input must be a non-negative integer");
  }
  if (n === 0 || n === 1) {
    return 1;
  }
  let result = 1;
  for (let i = 2; i <= n; i++) {
    result *= i;
  }
  return result;
}

const factorialValue = calculateFactorial(x);
console.log(`The factorial of ${x} is ${factorialValue}`);
